      "description": "Gmail label display names. This action accepts names and can create missing labels when create_missing_labels is true; batch_modify_email requires existing Gmail label IDs.",
      "anyOf": [
        {
          "type": "array",
          "items": {
            "type": "string"
          }
        },
        {
          "type": "null"
        }
