// * find: {"find": [{"ref_id": "turn0fetch3", "pattern": "Annie Case"}]}
// * finance: {"finance":[{"ticker":"AMD","type":"equity","market":"USA"}]}, {"finance":[{"ticker":"BTC","type":"crypto","market":""}]}
